import { useEffect } from 'react';
import './App.css';

function App() {

  useEffect(() => {
    fetch("https://newsapi.org/v2/everything?q=microsoft&apiKey=8047ab24c9464bacad8b9841cdd30f85")
      .then((response) => response.json())
      .then((data) => {
        console.log(data);
      })
      .catch((err) => {
        console.log(err);

      })
  }, [])


  return (
    <div className="App">
      <h1>News App</h1>
    </div>
  );
}

export default App;
